import Task from './Task';
import AssetManager from '../AssetManager';
import AssetUtils from '../AssetUtils';
import Callback from '../LoaderCallback';

/**
 * Internal class for grouping a list of tasks into one task.
 * ```
 * jibo.loader.load({
 *    assets: [
 *        { src: "data.json" },
 *        "image.png"
 *    ]
 * }, (err, results) => {});
 * ```
 * @class ListTask
 * @extends jibo.loader.Task
 * @intdocs
 * @memberof jibo.loader
 * @param {jibo.loader.AssetManager} manager Instance of AssetManager.
 * @param {Object} asset The data properties.
 * @param {Array|Object} asset.assets The collection of assets to load.
 * @param {Boolean} [asset.cacheAll=false] `true` to cache each item in assets.
 * @param {Boolean} [asset.remoteAll=false] `true` to force remote loading.
 * @param {Boolean} [asset.cache=false] `true` to cache the result.
 * @param {String} [asset.id] ID of asset.
 * @param {Function} [asset.complete=null] The event to call when done.
 * @param {Function} [asset.progress=null] The event to call when progress is updated.
 */
class ListTask extends Task
{
    static priority:number;
    public assets:any;
    public cacheAll:boolean;
    public remoteAll:boolean;
    public progress:(progress:number) => void;

    /**
     * Tests if this task should be run.
     * @method jibo.loader.ListTask.test
     * @static
     * @param {Object} asset The asset to check.
     * @return {Boolean} `true` if the asset is compatible with this asset.
     */
    static test(asset:any):boolean
    {
        return !!asset.assets && (Array.isArray(asset.assets) || AssetUtils.isPlain(asset.assets));
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset);

        /**
         * The collection of assets to load.
         * @type {Array|Object}
         * @name jibo.loader.ListTask#assets
         */
        this.assets = asset.assets;

        /**
         * `true` if each asset in the collection should be cached.
         * @type {Boolean}
         * @name jibo.loader.ListTask#cacheAll
         */
        this.cacheAll = asset.cacheAll;

        /**
         * `true` to force remote loading for all assets.
         * @type {Boolean}
         * @name jibo.loader.ListTask#remoteAll
         */
        this.remoteAll = asset.remoteAll;

        /**
         * Callback when progress is updated.
         * @type {Function}
         * @name jibo.loader.ListTask#progress
         */
        this.progress = asset.progress;
    }

    /**
     * Starts the task.
     * @method  jibo.loader.ListTask#start
     * @param  {jibo.loader.Task~completeCallback} callback Callback when finished.
     */
    start(callback:Callback): void
    {
        this.load(this.assets,
        {
            complete: callback,
            progress: this.progress,
            cacheAll: this.cacheAll,
            remoteAll: this.remoteAll
        });
    }

    /**
     * Destroys this and discards.
     * @method jibo.loader.ListTask#destroy
     */
    destroy(): void
    {
        super.destroy();
        this.assets = null;
    }
}

export default ListTask;
