/**
 * Error type when a load process fails.
 * @class LoaderError
 * @extends Error
 * @memberof jibo.loader
 */
class LoaderError extends Error
{
    public message: string;
    /**
     * The original loading error thrown, usually `fs`.
     * @name jibo.loader.LoaderError#originalError
     * @type {Error}
     */
    public originalError:any;
    /**
     * The full path to the file request. Combines the `basePath` with `asset.src`.
     * @name jibo.loader.LoaderError#request
     * @type {String}
     */
    public request:string;

    constructor(originalError:any, request:string, message?: string)
    {
        message = message ? message + ': ' + originalError.message : originalError.message;
        super(message);
        
        this.originalError = originalError;
        this.request = request;

        // Set the prototype explicitly. TypeScript 2.1
        Object.setPrototypeOf(this, LoaderError.prototype);

        /**
         * The name of the error type.
         * @name jibo.loader.LoaderError#name
         * @type {String}
         */
        this.name = 'LoaderError';

        /**
         * Error message.
         * @name jibo.loader.LoaderError#message
         * @type {String}
         */
        this.message = message || 'load error';

        /**
         * Stack trace for the error.
         * @name jibo.loader.LoaderError#stack
         * @type {String}
         */
        this.stack = (<any>new Error()).stack;
    }

    /**
     * Converts the error to a string.
     * @method jibo.loader.LoaderError#toString
     * @return {String} String representation of error.
     */
    toString():string
    {
        return this.name + ': ' + this.message;
    }
}

export default LoaderError;
