import Task from './Task';
import AssetManager from '../AssetManager';
import Callback from '../LoaderCallback';

/**
 * Internal class for dealing with async function calls with AssetManager.
 * ```
 * jibo.loader.load({
 *    async: (done) => {
 *        done();
 *    },
 * }, (err) => {});
 * ```
 * @class FunctionTask
 * @extends jibo.loader.Task
 * @memberof jibo.loader
 * @intdocs
 * @param {jibo.loader.AssetManager} manager Instance of AssetManager.
 * @param {Object} asset The data properties.
 * @param {Boolean} [asset.cache=false] `true` to cache the result.
 * @param {Function} asset.async The required function to call.
 * @param {Function} [asset.complete] The function to call when done.
 * @param {String} [asset.id] The task id for mapping the result, if any.
 */
class FunctionTask extends Task
{
    static priority:number;
    public async:Function;

    /**
     * Tests if the task should be run.
     * @method jibo.loader.FunctionTask.test
     * @static
     * @param {Object} asset The asset to check.
     * @return {Boolean} `true` if the asset is compatible with this task.
     */
    static test(asset:any):boolean
    {
        return !!asset.async;
    }

    constructor(manager:AssetManager, asset:any)
    {
        super(manager, asset);

        /**
         * The asynchronous call.
         * @type {Function}
         * @name jibo.loader.FunctionTask#async
         */
        this.async = asset.async;
    }

    /**
     * Starts the task.
     * @method jibo.loader.FunctionTask#start
     * @param {jibo.loader.Task~completeCallback} callback Callback when done.
     */
    start(callback:Callback):void
    {
        this.async(callback);
    }

    /**
     * Destroys this and discards.
     * @method jibo.loader.FunctionTask#destroy
     */
    destroy():void
    {
        super.destroy();
        this.async = null;
    }
}

export default FunctionTask;
