import AbstractLoader, {FILETYPE} from './AbstractLoader';
import Callback from '../LoaderCallback';
import ImageResource from './remote/ImageResource';
import TextResource from './remote/TextResource';
import Resource from './remote/Resource';
import BinaryResource from "./remote/BinaryResource";

/**
 * Loads all assets to a skill,
 * including images, data, code. RemoteLoader supports cache-busting
 * in the browser using dynamic query string parameters.
 * @class RemoteLoader
 * @memberof jibo.loader
 * @private
 */
export default class RemoteLoader extends AbstractLoader {

    /**
     * Base to append to all file requests.
     * @type {String}
     * @name jibo.loader.RemoteLoader#baseUrl
     */
    public baseUrl:string = '';

    /**
     * Prepares a url for usage based on the configuration of this object.
     * @method jibo.loader.RemoteLoader#prepare
     * @param {string} url - The url to prepare.
     * @return {string} The prepared url.
     */
    public prepare(url:string):string {

        // if baseUrl doesn't end in slash and url doesn't start with slash, then add a slash inbetween
        if (this.baseUrl.length
            && this.baseUrl.lastIndexOf('/') !== this.baseUrl.length - 1
            && url.charAt(0) !== '/'
        ) {
            return this.baseUrl + '/' + url;
        }
        return this.baseUrl + url;
    }

    /**
     * Loads the asset file.
     * @method jibo.loader.RemoteLoader#internalLoad
     * @protected
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     * @param {Object} [options] Optional load options
     */
    protected internalLoad(type:string, url:string, callback:Callback, options?:any): void
    {
        options = options || {};
        let resource:Resource;
        if (type === FILETYPE.IMAGE) {
            resource = new ImageResource(type, url, callback, options);
        }
        else if(type === FILETYPE.BINARY) {
            resource = new BinaryResource(type, url, callback, options);
        }
        else {
            resource = new TextResource(type, url, callback, options);
        }

        // Handle when the resource is complete
        resource.onComplete = (err:string, resource:Resource) => {
            // Handle any load errors
            if (err) {
                return resource.callback(this.createError(err, url));
            }
            // Handle javascript
            if (resource.type === FILETYPE.JAVASCRIPT) {
                const script = document.createElement('script');
                script.innerHTML = String(resource.result);
                script.dataset['url'] = resource.url;
                resource.callback(null, script);
            }
            // Just pass the image through if it loaded
            else if (resource.type === FILETYPE.IMAGE) {
                resource.callback(null, resource.result);
            }
            // Do the normal JSON and DOM parsing for other text files
            else {
                this.internalDone(
                    resource.type,
                    resource.url,
                    resource.result,
                    resource.callback
                );
            }
        };
        resource.start();
    }
}