import AssetCache from './AssetCache';
import AssetLoad from './AssetLoad';

/**
 * Class that represents a loaded or loading item, enabling strict unloading policies.
 * @class AssetToken
 * @memberof jibo.loader
 */
export default class AssetToken
{
    /**
     * Name of the named cache that this load was attached to.
     * @type {string}
     * @name jibo.loader.AssetToken#cache
     * @readonly
     */
    public readonly cache:string;
    /**
     * Unique id within the named cache that this load was attached to.
     * @type {string}
     * @name jibo.loader.AssetToken#id
     * @readonly
     */
    public readonly id:string;
    /**
     * Globally unique key used to cache this load.
     * @type {string}
     * @name jibo.loader.AssetToken#key
     * @readonly
     */
    public readonly key:string;
    /**
     * The AssetCache that this token will use to unload a loaded asset.
     * @private
     */
    public owner:AssetCache;
    /**
     * The loader that this token will use to cancel a load.
     * @private
     */
    public loader:AssetLoad;
    
    /**
     * If this token is valid. Tokens that have been unloaded are invalid.
     * @type {boolean}
     * @name jibo.loader.AssetToken#isValid
     * @readonly
     */
    public get isValid():boolean {
        return !!this.owner;
    }
    
    //constructor params are not documented, because this class is a public class but should not
    //be instantiated outside jibo-loader
    /**
     * @private
     */
    constructor(owner:AssetCache, key:string, cache:string, id:string)
    {
        if (!owner || !owner.delete)
        {
            throw new Error('AssetTokens must be instantiated with an owner!');
        }
        this.key = key;
        this.cache = cache;
        this.id = id;
        this.owner = owner;
        this.loader = null;
    }
    
    /**
     * Cancels any ongoing load (if still being loaded) and removes this load from the cache.
     * @method jibo.loader.AssetToken#unload
     */
    public unload()
    {
        if (this.loader)
        {
            this.loader.cancelToken(this);
        }
        if (this.owner)
        {
            this.owner.delete(this);
        }
        this.loader = null;
        this.owner = null;
    }
    
    /**
     * Alias for unload()
     * @method jibo.loader.AssetToken#cancel
     * @see jibo.loader.AssetToken#unload
     */
    public cancel()
    {
        this.unload();
    }
}