import {EventEmitter} from 'events';
import Task from './tasks/Task';
import {Complete} from './tasks/Task';
import AssetManager from './AssetManager';
import AssetUtils from './AssetUtils';
import AssetToken from './AssetToken';

import parentLog from './log';
const log = parentLog.createChild('AssetLoad');


export interface Asset {
    id?:string;
    cache?:string;
    complete?:Complete;
    remote?:boolean;
    timeout?:number;
    format?:string;
    type?:string;
    instance?:boolean;
    src?:string;
}

export interface ITaskDefinition {
    test: (asset:Asset) => boolean;
    priority: number;
    prototype: any;
    new (manager:AssetManager, asset:Asset) : Task;
}

export interface SetupOptions {
    maxLoads?:number;
    autoStart?:boolean;
    cacheAll?:string;
    remoteAll?:boolean;
    timeoutAll?:number;
}

export interface AssetResult {
    result?:any;
    subAssets?: AssetToken[];
    token:AssetToken;
}

/**
 * Class that represents a single multi load.
 * @class AssetLoad
 * @memberof jibo.loader
 */
class AssetLoad extends EventEmitter
{
    /**
     * Debugging Keep track of how many we've created
     * @type {int}
     * @name jibo.loader.AssetLoad.ID
     * @static
     * @private
     */
    private static ID:number;

    public manager:AssetManager;
    public id:number;
    public mode:number;
    public maxLoads:number;
    public tasks:Array<Task>;
    public results:any;
    public running:boolean;
    public numLoaded:number;
    public numLoading:number;
    public total:number;
    public cacheAll:string;
    public remoteAll:boolean;
    public timeoutAll:number;
    public loadedTokens:AssetToken[];

    /**
     * @constructor
     * @param {jibo.loader.AssetManager} manager Reference to the manager.
     * @private
     */
    constructor(manager:AssetManager)
    {
        super();

        /**
         * Reference to the Task Manager.
         * @type {jibo.loader.AssetManager}
         * @name jibo.loader.AssetLoad#manager
         * @private
         */
        this.manager = manager;

        this.id = AssetLoad.ID++;

        /**
         * How to display the results, either as single (0), map (1) or list (2).
         * @type {int}
         * @name jibo.loader.AssetLoad#mode
         * @default 1
         * @private
         */
        this.mode = MAP_MODE;

        /**
         * The maximum number of loads, 0 for no max limit (all at once)
         * @type {Number}
         * @name jibo.loader.AssetLoad#maxLoads
         * @readOnly
         * @private
         */
        this.maxLoads = 0;

        /**
         * Name of cache to apply to all items in the load
         * @type {String}
         * @name jibo.loader.AssetLoad#cacheAll
         * @default null
         * @private
         */
        this.cacheAll = null;

        /**
         * `true` if we load all the resources remotely.
         * @type {Boolean}
         * @name jibo.loader.AssetLoad#remoteAll
         * @default false
         * @private
         */
        this.remoteAll = false;

        /**
         * Number of milliseconds to timeout all remote requests
         * @type {Number}
         * @name jibo.loader.AssetLoad#timeoutAll
         * @default 0
         * @private
         */
        this.timeoutAll = 0;

        /**
         * Items that have already been loaded and added to the cache. Stored for removal
         * if the load is canceled before completion, as well accessing by the code that initiated
         * the load.
         * @type {jibo.loader.AssetToken[]}
         * @name jibo.loader.AssetLoad#loadedTokens
         * @private
         */
        this.loadedTokens = [];

        /**
         * The list of tasks to load.
         * @type {Array<jibo.loader.Task>}
         * @name jibo.loader.AssetLoad#tasks
         * @private
         */
        this.tasks = [];

        /**
         * The results to return when we're done.
         * @type {Array|Object}
         * @name jibo.loader.AssetLoad#results
         */
        this.results = null;

        /**
         * `true` if the load is currently running.
         * @type {Boolean}
         * @name jibo.loader.AssetLoad#running
         * @default false
         */
        this.running = false;

        /**
         * The total number of assets loaded.
         * @type {int}
         * @name jibo.loader.AssetLoad#numLoaded
         * @default 0
         * @readOnly
         * @private
         */
        this.numLoaded = 0;

        /**
         * The current number of .
         * @type {int}
         * @name jibo.loader.AssetLoad#numLoading
         * @default 0
         * @readOnly
         * @private
         */
        this.numLoading = 0;

        /**
         * The total number of assets.
         * @type {int}
         * @name jibo.loader.AssetLoad#total
         * @default 0
         * @readOnly
         * @private
         */
        this.total = 0;
    }

    /**
     * When an asset is finished.
     * @event jibo.loader.AssetLoad#taskDone
     * @param {*} result The loader result.
     * @param {object} originalAsset The original load asset.
     * @param {jibo.loader.AssetLoad} load This loader to add additional assets to.
     */

    /**
     * When all assets have been completely loaded.
     * @event jibo.loader.AssetLoad#complete
     * @param {Array|Object} results The results of load.
     */

    /**
     * Checks how many assets have finished loading.
     * @event jibo.loader.AssetLoad#progress
     * @param {number} percentage The amount loaded from 0 to 1.
     */
    
    /**
     * List of AssetToken objects for all loads that will be or have been performed.
     * @type {jibo.loader.AssetToken[]}
     * @name jibo.loader.AssetLoad#tokens
     */
    public get tokens():AssetToken[]
    {
        const output:AssetToken[] = [];
        //get tokens from pending tasks
        if (this.tasks) {
            this.tasks.forEach((task) => {
                if (task.token) {
                    output.push(task.token);
                }
            });
        }
        //get tokens from completed tasks
        if (this.loadedTokens) {
            output.push(...this.loadedTokens);
        }
        //filter out any nulls that might sneak in there
        return output.filter(item => !!item);
    }

    /**
     * Debugging purposes.
     * @method jibo.loader.AssetLoad#toString
     * @return {String}
     * @private
     */
    toString(): string
    {
        return "[AssetLoad (index: " + this.id + ")]";
    }

    /**
     * Initializes the Load.
     * @method jibo.loader.AssetLoad#setup
     * @param {object|array} assets The collection of assets to load.
     * @param {object} [options] The loading options.
     * @param {Number} [options.maxLoads=4] `0` to start all load requests at once, any other to limit.
     * @param {Boolean} [options.autoStart=true] `true` to start running automatically.
     * @param {Boolean|String} [options.cacheAll=false] `true` to cache all load results, `false` to allow assets to cache themselves.
     * @param {Boolean|String} [options.remoteAll=false] `true` to make all requests remote, `false` to allow assets to remote themselves.
     * @private
     */
    setup(assets:Array<Asset>|{[id:string]: Asset}, options?:SetupOptions): void
    {
        // Save options to load
        this.maxLoads = options.maxLoads;
        this.cacheAll = options.cacheAll;
        this.remoteAll = options.remoteAll;
        this.timeoutAll = options.timeoutAll;

        // Update the results mode and tasks
        this.mode = this.addTasks(assets);

        // Set the default container for the results
        this.results = this.getAssetsContainer(this.mode);

        // Start running
        if (options.autoStart)
        {
            this.start();
        }
    }

    /**
     * Cancel the load progress.
     * @method jibo.loader.AssetLoad#cancel
     */
    cancel(): void
    {
        this.loadedTokens.forEach((token) => {
            this.manager.cache.delete(token);
        });
        this.manager.cancel(this);
    }
    
    /**
     * Cancel the load progress.
     * @method jibo.loader.AssetLoad#cancelToken
     * @private
     */
    cancelToken(token:AssetToken): void
    {
        //remove from the list of cached things
        let index = this.loadedTokens.indexOf(token);
        if (index !== -1) {
            this.loadedTokens.splice(index, 1);
        }
        //find the task that was loading this item
        index = this.tasks.findIndex((item) => {
            return item.token === token;
        });
        if (index !== -1) {
            this.tasks.splice(index, 1);
        }
        //if we have no more tasks, then we should just cancel this whole AssetLoad
        if (this.tasks.length === 0) {
            if (this.loadedTokens.length === 0) {
                this.cancel();
            } else {
                // We're finished!
                this.emit('complete', null, this.results);
            }
        }
    }

    /**
     * Starts the load process.
     * @method jibo.loader.AssetLoad#start
     */
    start(): void
    {
        // Empty load percentage
        this.emit('progress', 0);

        // Keep track if we're currently running
        this.running = true;
        this.nextTask();
    }

    /**
     * Sets back to the original state.
     * @method jibo.loader.AssetLoad#reset
     * @private
     */
    reset()
    {
        this.removeAllListeners('complete');
        this.removeAllListeners('progress');
        this.removeAllListeners('taskDone');
        // Cancel any tasks
        this.tasks.forEach((task) =>
        {
            if (task.pending) {
                this.manager.cache.cancelPending(task.token);
            }
            task.status = Task.FINISHED;
            task.destroy();
        });
        this.total = 0;
        this.numLoaded = 0;
        this.numLoading = 0;
        this.mode = MAP_MODE;
        this.tasks.length = 0;
        this.results = null;
        this.maxLoads = 0;
        this.cacheAll = null;
        this.remoteAll = false;
        this.timeoutAll = 0;
        this.running = false;
        this.loadedTokens.length = 0;
    }
    
    /**
     * Adds loads to an ongoing load. Call this during callbacks/events for individual task
     * completion.
     * @method  jibo.loader.AssetLoad#addAssets
     * @param  {Object|Array} assets The assets to load.
     * @return {jibo.loader.AssetToken[]} The asset tokens of the newly added assets (if they are cached).
     */
    public addAssets(assets:Asset|Array<Asset>|{[id:string]: Asset}): AssetToken[]
    {
        const output:AssetToken[] = [];
        this.addTasks(assets, output);
        return output;
    }

    /**
     * Creates a list of tasks from assets.
     * @method  jibo.loader.AssetLoad#addTasks
     * @private
     * @param  {Object|Array} assets The assets to load.
     * @param {jibo.loader.AssetToken[]} [tokenOut] An array to add new asset tokens to.
     */
    addTasks(assets:Asset|Array<Asset>|{[id:string]: Asset}, tokenOut?:AssetToken[]): number
    {
        let asset;
        let mode = MAP_MODE;

        // Apply the defaults incase this is a single
        // thing that we're trying to load
        assets = this.applyDefaults(assets);

        let isSingle = !!this.getTaskByAsset(assets as any);

        if (isSingle)
        {
            const task = this.addTask(<Asset>assets);
            if (tokenOut && task.token) {
                tokenOut.push(task.token);
            }
            return SINGLE_MODE;
        }
        else
        {
            let task;
            if (Array.isArray(assets))
            {
                for (let i = 0; i < assets.length; i++)
                {
                    asset = this.applyDefaults(assets[i]);
                    task = this.addTask(asset);
                    if (tokenOut && task.token) {
                        tokenOut.push(task.token);
                    }
                    if (!task.id)
                    {
                        // If we don't have the id to return
                        // a mapped result, we'll fallback to array results
                        mode = LIST_MODE;
                    }
                }
            }
            else if (AssetUtils.isPlain(assets))
            {
                for (let id in assets)
                {
                    asset = this.applyDefaults(assets[id]);
                    asset.id = id;
                    task = this.addTask(asset);
                    if (tokenOut && task.token) {
                        tokenOut.push(task.token);
                    }
                }
            }
            else
            {
                log.debug("Asset type unsupported", asset);
            }
        }
        return mode;
    }

    /**
     * Converts assets into object defaults.
     * @method jibo.loader.AssetLoad#applyDefaults
     * @private
     * @static
     * @param  {*} asset The function to convert.
     * @return {Object} The object asset to use.
     */
    applyDefaults(asset:any):any
    {
        // convert to a LoadTask
        if (isString(asset))
        {
            return {
                src: asset
            };
        }
        // convert to a FunctionTask
        else if (isFunction(asset))
        {
            return {
                async: asset
            };
        }
        return asset;
    }

    /**
     * Loads a single asset.
     * @method jibo.loader.AssetLoad#addTask
     * @private
     * @param {Object} asset The asset to load.
     *      Can either be an object, URL/path, or async function.
     * @return {Task} New task instance.
     */
    addTask(asset:Asset):Task
    {
        let TaskClass = this.getTaskByAsset(asset);
        let task:Task;
        if (TaskClass)
        {
            if (asset.cache === undefined && this.cacheAll)
            {
                asset.cache = this.cacheAll;
            }
            if (asset.remote === undefined && this.remoteAll)
            {
                asset.remote = true;
            }
            if (asset.timeout === undefined && this.timeoutAll)
            {
                asset.timeout = this.timeoutAll;
            }
            task = new TaskClass(this.manager, asset);
            this.tasks.push(task);
            ++this.total;
            
            if (!task.cache && task.needsCache)
            {
                //console message because it is really a dev thing that we don't need in syslog
                console.error('Trying to load %o but it needs to be cached!', task.original);
            } else if (task.cache) {
                task.token = this.manager.cache.prepare(task.cacheKey, task.cache, task.id);
                task.token.loader = this;
            }
        }
        else
        {
            log.debug("Unable to find a task definition for asset", asset);
        }
        return task;
    }

    /**
     * Gets the Task definition for an asset.
     * @method  jibo.loader.AssetLoad#getTaskByAsset
     * @private
     * @static
     * @param  {Object} asset The asset to check.
     * @return {Function} The Task class.
     */
    getTaskByAsset(asset:Asset):ITaskDefinition
    {
        let TaskClass:ITaskDefinition;
        let taskDefs = this.manager.taskDefs;

        // Loop backwards to get the registered tasks first
        // then will default to the basic Loader task
        for (let i = 0, len = taskDefs.length; i < len; i++)
        {
            TaskClass = taskDefs[i];
            if (TaskClass.test(asset))
            {
                return TaskClass;
            }
        }
        return null;
    }

    /**
     * Runs the next task that's waiting.
     * @method  jibo.loader.AssetLoad#nextTask
     * @private
     */
    nextTask(): void
    {
        // const task:Task = this.tasks.shift();
        let task:Task;

        // Find the first task that's not pending
        for (let i = 0; i < this.tasks.length; i++)
        {
            if (this.tasks[i].status === Task.WAITING)
            {
                task = this.tasks[i];
                break;
            }
        }

        // No tasks left or task is already queued-up
        if (!task)
        {
            return;
        }

        task.status = Task.RUNNING;
        this.numLoading++;

        // Don't reload assets already in the cache
        // only check the cache for things that would go in the cache - don't want to interfere with
        // different task types that use the same src but different outputs (looking at you, .keys)
        if (task.cache && this.manager.cache.isLoaded(task.cacheKey))
        {
            process.nextTick(() => {
                const result = this.manager.cache.read(task.cacheKey);
                if (this.manager.cache.wasError(task.cacheKey)) {
                    this.taskDone(task, result, null);
                } else {
                    this.taskDone(task, null, result);
                }
            });
        }
        else
        {
            if (task.cache) {
                task.pending = this.taskDone.bind(this, task);
                const assetData:AssetResult = {
                    token: task.token
                };
                //add callback/create initial asset if needed
                const needsStart = this.manager.cache.addPending(task.token, task.pending);
                if (needsStart) {
                    //if it was not previously pending, start the task
                    task.start((err, result) => {
                        //If the task was cancelled, don't do stuff
                        if (task.status !== Task.RUNNING) {
                            if (result && result.destroy) {
                                result.destroy();
                            }
                            return;
                        }
                        assetData.result = result;
                        assetData.subAssets = task.subAssets;
                        //add the result to the cache and perform all pending callbacks (including
                        //the one for this task)
                        this.manager.cache.completePending(err, assetData);
                    });
                }
                //manage our returned token
                assetData.token = task.token;
            } else {
                //just load the task the simple way
                task.start(this.taskDone.bind(this, task));
            }
        }

        // If there's no limit or we can queue more tasks
        if (this.maxLoads === 0 || this.numLoading < this.maxLoads)
        {
            this.nextTask();
        }
    }

    /**
     * Handler when a task has completed.
     * @method  jibo.loader.AssetLoad#taskDone
     * @private
     * @param  {Task} task Reference to original task.
     * @param {Error} err The error thrown by load.
     * @param  {*} [result] The result of load.
     */
    taskDone(task:Task, err:Error, result:any = null): void
    {
        // Ignore if we're destroyed
        if (!this.running)
        {
            return;
        }

        let index = this.tasks.indexOf(task);

        // Task was already removed, because a clear
        if (index === -1)
        {
            return;
        }
        
        //track the cache token used
        if (task.cache)
        {
            this.loadedTokens.push(task.token);
        }

        // Remove the completed task
        this.tasks.splice(index, 1);

        // Assets
        let assets = [];

        log.iferr(err, 'error executing task');

        // Handle the file load tasks
        if (result)
        {
            // Handle the result
            switch (this.mode)
            {
                case SINGLE_MODE:
                    this.results = result;
                    break;
                case LIST_MODE:
                    this.results.push(result);
                    break;
                case MAP_MODE:
                    this.results[task.id] = result;
                    break;
            }
        }

        // If the task has a complete method
        // we'll make sure that gets called
        // with a reference to the tasks
        // can potentially add more
        if (task.complete)
        {
            task.complete(err, result, task.original, this);
        }

        if (!err)
        {
            this.emit('taskDone', result, task.original, this);
        }

        task.destroy();

        // Add new assets to the things to load
        let mode = this.addTasks(assets);

        // Update the progress total
        this.emit('progress', ++this.numLoaded / this.total);

        // Complete a task
        --this.numLoading;

        // Check to make sure if we're in
        // map mode, we keep it that way
        if (this.mode === MAP_MODE && mode !== this.mode)
        {
            log.error("Load assets require IDs to return mapped results", assets);
            return;
        }

        // There was an error, pass it along
        if (err)
        {
            this.emit('complete', err, null);
            return;
        }

        if (this.tasks.length)
        {
            // Run the next task
            this.nextTask();
        }
        else
        {
            // We're finished!
            this.emit('complete', err, this.results);
        }
    }

    /**
     * Gets an empty assets collection.
     * @method jibo.loader.AssetLoad#getAssetsContainer
     * @private
     * @param {int} mode The mode.
     * @return {Array|Object|null} Empty container for assets.
     */
    getAssetsContainer(mode:number): Array<Asset>|{[id:string]: Asset}
    {
        switch (mode)
        {
            case SINGLE_MODE:
                return null;
            case LIST_MODE:
                return [];
            case MAP_MODE:
                return {};
        }
    }

    /**
     * Destroys this and discards.
     * @private
     * @method jibo.loader.AssetLoad#destroy
     */
    destroy()
    {
        this.removeAllListeners();
        this.reset();
        this.tasks = null;
        this.manager = null;
    }
}

/**
 * The result is a single result.
 * @property {int} jibo.loader.AssetLoad.SINGLE_MODE
 * @private
 * @final
 * @static
 * @default 0
 */
const SINGLE_MODE:number = 0;

/**
 * The result is a map of result objects.
 * @property {int} jibo.loader.AssetLoad.MAP_MODE
 * @private
 * @final
 * @static
 * @default 1
 */
const MAP_MODE:number = 1;

/**
 * The result is an array of result objects.
 * @property {int} jibo.loader.AssetLoad.LIST_MODE
 * @private
 * @final
 * @static
 * @default 2
 */
const LIST_MODE:number = 2;

/**
 * Checks if an object is a String type.
 * @method jibo.loader.AssetLoad.isString
 * @private
 * @param  {*}  obj The object to check.
 * @return {Boolean} `true` if object is a String, `false` otherwise.
 */
function isString(obj): obj is string
{
    return typeof obj === "string";
}

/**
 * Checks if an object is a function type.
 * @method jibo.loader.AssetLoad.isFunction
 * @private
 * @param  {*}  obj The object to check.
 * @return {Boolean} `true` if object is a function, `false` otherwise.
 */
function isFunction(obj)
{
    return typeof obj === "function";
}

export default AssetLoad;
