import {AssetResult} from './AssetLoad';
import AssetManager from './AssetManager';
import AssetToken from './AssetToken';

import parentLog from './log';
const log = parentLog.createChild('AssetCache');

export type AssetCallback = (err:any, content:any) => void;

/**
 * Internal class to represent a cached item
 * Saves a reference to the original URL request
 * and the content.
 * @private
 * @class CacheItem
 * @memberof jibo.loader
 * @param {String} request Full path requested
 * @param {any} content Result of the load.
 */
export class CacheItem
{
    /**
     * Set of tokens referencing this asset.
     * @name jibo.loader.CacheItem#tokens
     * @type {Set<AssetToken>}
     */
    public tokens:Set<AssetToken>;

    /**
     * Name and cache of items loaded from this item, so that they can be unloaded with it.
     * @name jibo.loader.CacheItem#subAssets
     * @type {AssetToken[]}
     */
    public subAssets:AssetToken[];

    /**
     * The cached content.
     * @name jibo.loader.CacheItem#content
     * @type {any}
     */
    public content:any;

    /**
     * Callbacks for completion of a pending load.
     * @name jibo.loader.CacheItem#pendingCallbacks
     * @type {Function[]}
     */
    public pendingCallbacks:Map<AssetToken, AssetCallback>;

    /**
     * If the content variable contains an error rather than an actual result.
     * @name jibo.loader.CacheItem#contentIsError
     * @type {boolean}
     */
    public contentIsError:boolean;

    constructor(public key:string)
    {
        //having the pending callbacks array means the asset is pending
        this.pendingCallbacks = new Map();
        // initial reference count
        this.tokens = new Set();
        this.contentIsError = false;
        this.content = null;
        this.subAssets = null;
    }

    /**
     * If the item load is currently in progress.
     * @name jibo.loader.CacheItem#isPending
     * @type {boolean}
     * @readOnly
     */
    public get isPending():boolean
    {
        return !this.content;
    }

    /**
     * Adds a callback to be called when the load completes.
     * @method jibo.loader.CacheItem#addPending
     * @param {jibo.loader.AssetToken} token Token attached to this callback
     * @param {Function} callback Callback for when the load completes.
     */
    public addPending(token:AssetToken, callback:AssetCallback)
    {
        this.pendingCallbacks.set(token, callback);
    }

    /**
     * Removes a pending callback.
     * @method jibo.loader.CacheItem#removePending
     * @param {Function} token Token of a pending asset load to remove.
     */
    public removePending(token:AssetToken)
    {
        if (!this.pendingCallbacks)
        {
            return;
        }
        if (this.pendingCallbacks.has(token))
        {
            this.pendingCallbacks.delete(token);
        }
        if (this.tokens.has(token))
        {
            this.tokens.delete(token);
        }
    }

    /**
     * Adds the loaded content and any subAssets loaded during the load.
     * @method jibo.loader.CacheItem#completeLoad
     */
    public completeLoad(err:any, content:any, subAssets:AssetToken[]) {
        this.content = content;
        this.subAssets = subAssets || null;
        this.contentIsError = !!err;

        //call pending callbacks:
        const callbacks = Array.from(this.pendingCallbacks.values());
        this.pendingCallbacks.clear();
        for (let callback of callbacks) {
            callback(err, content);
        }
    }

    /**
     * Destroy the content, don't use after this.
     * @method jibo.loader.CacheItem#destroy
     * @param {jibo.loader.AssetCache} cache The main asset cache so that sub assets can be unloaded.
     */
    public destroy(cache:AssetCache):void
    {
        // Destroy any objects with a destroy function
        if (this.content && this.content.destroy)
        {
            this.content.destroy(true);
        }

        // Clear images if we have an HTML node
        if (this.content && this.content.tagName === 'IMG')
        {
            this.content.src = '';
        }
        this.content = null;
        this.key = null;
        //tell sub assets to unload, as we are now done with them
        if (this.subAssets)
        {
            for (let i = 0; i < this.subAssets.length; ++i)
            {
                cache.delete(this.subAssets[i]);
            }
            this.subAssets = null;
        }
        this.pendingCallbacks = null;
    }
}

/**
 * Internal class to represent a specific cache that items are loaded into. This allows for easier
 * unloading of a whole group of items.
 * @private
 * @class NamedCache
 * @memberof jibo.loader
 * @param {String} name Name of the cache.
 */
class NamedCache
{
    /**
     * The name of the cache.
     * @type {String}
     * @name jibo.loader.NamedCache#name
     */
    public name: string;
    /**
     * A map of asset ids to asset keys.
     * @type {Object}
     * @name jibo.loader.NamedCache#idMap
     */
    public idMap: Map<string, string>;
    /**
     * The set of loads attached to this cache.
     * @type {Object}
     * @name jibo.loader.NamedCache#tokens
     */
    public tokens: Set<AssetToken>;

    constructor(name:string)
    {
        this.name = name;
        this.idMap = new Map<string, string>();
        this.tokens = new Set<AssetToken>();
    }

    /**
     * Marks an item as loaded one time within this cache.
     * @method jibo.loader.NamedCache#load
     * @param {jibo.loader.AssetToken} token Shorthand id that the item was loaded under.
     */
    public load(token:AssetToken):void
    {
        //track what key the id goes to
        const {id, key} = token;
        if (this.idMap.has(id) && this.idMap.get(id) !== key)
        {
            log.info(`In cache ${this.name} overwriting asset ${id} with key of ${this.idMap.get(id)} with new key of ${key}`);
        }
        this.idMap.set(id, key);
        //keep track of how many times it has shown up in this cache
        this.tokens.add(token);
    }

    /**
     * Removes one loaded mark for an item within this cache.
     * @method jibo.loader.NamedCache#unload
     * @param {jibo.loader.AssetToken} token Token by which
     */
    public unload(token:AssetToken):void
    {
        this.tokens.delete(token);
        const {id} = token;
        //if the id is not used anymore, remove it
        const otherTokens = this.tokens.values();
        let otherId = false;
        for (let item of otherTokens)
        {
            if (item.id === id)
            {
                otherId = true;
                break;
            }
        }
        if (!otherId)
        {
            this.idMap.delete(id);
        }
    }
}

/**
 * Manages a cache for assets.
 * @class AssetCache
 * @memberof jibo.loader
 * @private
 */
export default class AssetCache
{
    /**
     * The cache containing assets.
     * @type {Object}
     * @name jibo.loader.AssetCache#_cache
     */
    private _cache:Map<string, CacheItem>;
    /**
     * A map of the current named caches
     * @type {Object}
     * @name jibo.loader.AssetCache#_cachesMap
     */
    private _cachesMap:Map<string, NamedCache>;
    /**
     * A reference to the owning asset manager.
     * @type {jibo.loader.AssetManager}
     * @name jibo.loader.AssetCache#_manager
     */
    private _manager:AssetManager;

    constructor(manager:AssetManager)
    {
        this._manager = manager;
        this._cache = new Map<string, CacheItem>();
        this._cachesMap = new Map<string, NamedCache>();
    }

    /**
     * Add a named cache to load items with.
     * @method jibo.loader.AssetCache#addCache
     * @param {String} id The cache id to add.
     */
    addCache(id:string): void
    {
        if (this._cachesMap.has(id))
        {
            //silently ignore re-adding caches, since we don't actually remove them
            return;
        }
        this._cachesMap.set(id, new NamedCache(id));
    }

    /**
     * Retrieves a single asset from the cache.
     * @method jibo.loader.AssetCache#read
     * @param {String} id The asset to get. If no cacheId, then this must be the unique id (usually the absolute source path).
     * @param {String} [cacheId] Cache ID to specify.
     * @return {any} Result or null, if no asset
     */
    read(id:string, cacheId?:string): any
    {
        if (!cacheId)
        {
            const item = this._cache.get(id);
            return item ? item.content : null;
        }
        const cache = this._cachesMap.get(cacheId);
        if (!cache)
        {
            throw new Error(`AssetCache.read(): unable to find cache: '${cacheId}'`);
        }
        const item = this._cache.get(cache.idMap.get(id));
        return item ? item.content : null;
    }

    /**
     * Dermines if a single asset from the cache is loaded or not.
     * @method jibo.loader.AssetCache#isLoaded
     * @param {String} id The asset to get. If no cacheId, then this must be the unique id (usually the absolute source path).
     * @param {String} [cacheId] Cache ID to specify.
     * @return {boolean} If the item is fully loaded
     */
    isLoaded(id:string, cacheId?:string): boolean
    {
        if (!cacheId)
        {
            const item = this._cache.get(id);
            return item ? !item.isPending : false;
        }
        const cache = this._cachesMap.get(cacheId);
        if (!cache)
        {
            throw new Error(`AssetCache.isLoaded(): unable to find cache: '${cacheId}'`);
        }
        const item = this._cache.get(cache.idMap.get(id));
        return item ? !item.isPending : false;
    }

    /**
     * Determines if a single asset from the cache has been loaded, but was a failure to load.
     * @method jibo.loader.AssetCache#wasError
     * @param {String} id The asset to get. If no cacheId, then this must be the unique id (usually the absolute source path).
     * @param {String} [cacheId] Cache ID to specify.
     * @return {boolean} If the item is fully loaded but was an error
     */
    wasError(id:string, cacheId?:string): boolean
    {
        if (!cacheId)
        {
            const item = this._cache.get(id);
            return item ? item.contentIsError : false;
        }
        const cache = this._cachesMap.get(cacheId);
        if (!cache)
        {
            throw new Error(`AssetCache.wasError(): unable to find cache: '${cacheId}'`);
        }
        const item = this._cache.get(cache.idMap.get(id));
        return item ? item.contentIsError : false;
    }

    /**
     * Prepares a single asset in the cache to have content written later.
     * @method jibo.loader.AssetCache#prepare
     * @param {string} key Unique key that the asset will be stored under.
     * @param {string} cacheName Name of the named cache that the asset will be stored under.
     * @param {string} id Id that the asset will be stored in the named cache under.
     * @returns {jibo.loader.AssetToken} A unique token representing this load of the asset. Use this to unload the asset later.
     */
    prepare(key:string, cacheName:string, id:string): AssetToken
    {
        const cache = this._cachesMap.get(cacheName);
        if (!cache)
        {
            throw new Error(`AssetCache.prepare(): unable to find cache: '${cacheName}'`);
        }
        const token = new AssetToken(this, key, cacheName, id);
        cache.load(token);
        //add the callback, creating an item if needed
        let cacheItem = this._cache.get(key);
        if (!cacheItem)
        {
            cacheItem = new CacheItem(key);
            this._cache.set(key, cacheItem);
        }
        cacheItem.tokens.add(token);
        return token;
    }

    /**
     * Prepares a single asset in the cache to have content written later.
     * @method jibo.loader.AssetCache#addPending
     * @param {AssetToken} token The AssetResult type object from the AssetLoad.
     * @param {Function} callback Callback to call when the asset has been loaded.
     * @returns {boolean} true if this was the first pending callback added, false if it was already pending
     */
    addPending(token:AssetToken, callback:AssetCallback): boolean
    {
        let cacheItem = this._cache.get(token.key);
        if (!cacheItem)
        {
            throw new Error(`AssetCache.addPending(): unable to find item: '${token.key}'`);
        }
        //add the callback, creating an item if needed
        let isFirst = cacheItem.pendingCallbacks.size === 0;
        cacheItem.addPending(token, callback);
        return isFirst;
    }

    /**
     * Removes a callback from a pending item.
     * @method jibo.loader.AssetCache#cancelPending
     * @param {jibo.loader.AssetToken} token The token that was created when the asset began loading.
     */
    cancelPending(token:AssetToken): void
    {
        //remove the item, if present
        let cacheItem = this._cache.get(token.key);
        if (!cacheItem)
        {
            return;
        }
        cacheItem.removePending(token);
        if (cacheItem.tokens.size === 0) {
            this._cache.delete(token.key);
        }
    }

    /**
     * Adds loaded content to an item in the cache, and tells it to call pending callbacks.
     * @method jibo.loader.AssetCache#completePending
     * @param {any} err A load error.
     * @param {AssetResult} result The AssetResult type object from the AssetLoad.
     */
    completePending(err:any, result:AssetResult): void
    {
        const {token} = result;
        //if the token was already unloaded, then bail, because we have no reason to throw an error
        if (!token.isValid) {
            return;
        }
        const cache = this._cachesMap.get(token.cache);
        if (!cache)
        {
            throw new Error(`AssetCache.completePending(): unable to find cache: '${token.cache}'`);
        }
        //complete load on the item in the cache
        let cacheItem = this._cache.get(token.key);
        if (cacheItem)
        {
            cacheItem.completeLoad(err, result.result, result.subAssets);
        }
        else
        {
            log.warn(`completePending() - unable to complete load for ${token.key} because no item was found`);
        }
    }

    /**
     * Removes a single asset from the cache.
     * @method jibo.loader.AssetCache#delete
     * @param {Object|String} assetOrId The asset to remove, or id of asset.
     * @param {String} cacheId Cache to specify
     */
    delete(token:AssetToken): void
    {
        const cacheId = token.cache;
        const cache = this._cachesMap.get(cacheId);
        if (cache)
        {
            //unload the item from the named cache
            cache.unload(token);
        }
        //do an unload of the item itself
        this.unloadItem(token);
    }

    /**
     * Removes all assets from the cache.
     * @method jibo.loader.AssetCache#empty
     * @param {string} [cacheId] The optional cache
     */
    empty(cacheId:string): void
    {
        const cache = this._cachesMap.get(cacheId);
        if (!cache)
        {
            return;
        }
        //unload everything by the number of times it was loaded
        for (let entry of cache.tokens.values())
        {
            //unload the entry AND cancel it if it is still loading
            entry.unload();
        }
        //clear the maps
        cache.idMap.clear();
        cache.tokens.clear();
    }

    /**
     * Destroys the cache. Don't use after this.
     * @method jibo.loader.AssetCache#destroy
     */
    destroy(): void
    {
        for (let id in this._cachesMap)
        {
            this.empty(id);
        }
        this._cache = null;
        this._cachesMap = null;
    }

    private unloadItem(token:AssetToken):void
    {
        const item:CacheItem = this._cache.get(token.key);
        if (item)
        {
            // decrement the ref-counter
            item.tokens.delete(token);

            // Destroy when no more references are left
            // or if we're forcing delete
            if (item.tokens.size < 1)
            {
                item.destroy(this);
                this._cache.delete(token.key);
            }
        }
    }
}
